#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use File::Basename;
use File::Spec;

my $cgi = CGI->new();
my $log_dir = '/path/to/log/directory';
my $filename = $cgi->param('logfile');

# Canonicalize and validate file paths
my $resolved_path = File::Spec->rel2abs($filename);
if (!-e $resolved_path || !-f $resolved_path) {
    print "Content-type: text/plain\n\n";
    print "Error: Log file not found.";
    exit;
}

# Ensure the resolved path stays within the intended base directory
my $base_dir = dirname($log_dir);
if (substr($resolved_path, 0, length($base_dir)) ne $base_dir) {
    print "Content-type: text/plain\n\n";
    print "Error: Log file is outside of allowed directory.";
    exit;
}

# Open the log file and display content
open(my $FH, "<$log_dir/$filename") or die "Could not open file '$log_dir/$filename' ($!)";

print "Content-type: text/plain\n\n";
while (my $line = <$FH>) {
    print "$line";
}
close($FH);